export const getCityBySlug = (slug: string): CityData | undefined => {
  return cities.find(city => city.slug === slug);
};

export const getNearbyCities = (currentSlug: string, limit: number = 4): CityData[] => {
  const current = getCityBySlug(currentSlug);
  if (!current) return cities.slice(0, limit);
  
  // Sort by distance and exclude current city
  return cities
    .filter(city => city.slug !== currentSlug)
    .sort((a, b) => {
      const distA = Math.sqrt(
        Math.pow(a.coords.lat - current.coords.lat, 2) + 
        Math.pow(a.coords.lng - current.coords.lng, 2)
      );
      const distB = Math.sqrt(
        Math.pow(b.coords.lat - current.coords.lat, 2) + 
        Math.pow(b.coords.lng - current.coords.lng, 2)
      );
      return distA - distB;
    })
    .slice(0, limit);
};
